INSERT IGNORE INTO movie_genres (movie_id, genre_id) SELECT m.id, g.id FROM movies m JOIN genres g ON FIND_IN_SET(g.name, REPLACE(m.genre, ', ', ',')) > 0 WHERE m.id BETWEEN 3001 AND 3199;
